mapper.select:
/* com.shop.mapper.frontWeb.display.selectContentsInfoListPaging */ SELECT CN.ID AS id , CN.NEWS_TYPE AS newsType , CN.NEWS_TITLE AS newsTitle , CN.NEWS_SUB_TITLE AS newsSubTitle , CN.NEWS_CONTENTS AS newsContents , CN.FILE_ID AS fileId , CN.PARTNER_ID AS partnerId , CN.DISPLAYSEQ AS displaySeq FROM TB_CONTENTS CN
AND CN.DEL_YN = 'N'
ORDER BY CN.ID LIMIT #{pageRowCount} + 1;
